  markdown?: Record<string, string>;
}

export interface ProjectMemory {
  root: string;
  name: string;
  updated_at: string;
  scan: ProjectScan;
  analysis: ProjectAnalysis;
  history?: unknown[];
}

export interface ProjectScan {
  root: string;
  name: string;
  total_files: number;
  total_dirs: number;
  total_bytes: number;
  total_lines: number;
  languages: Record<string, number>;
  language_lines: Record<string, number>;
  frameworks: string[];
  package_managers: string[];
  entry_points: string[];
  config_files: string[];
  dependencies: Record<string, string[]>;
  todo_comments: { tag: string; text: string; line: string; path: string }[];
  largest_files: {
    path: string;
    size: number;
    lines: number;
    language?: string;
  }[];
  tree: string;
  sample_files: {
    path: string;
    language: string;
    content: string;
    truncated: boolean;
  }[];
  readme_excerpt?: string;
  notes: string[];
}

export interface ProjectAnalysis {
  overview: string;
  architecture: string;
  patterns: string[];
  modules: { name: string; purpose: string; files?: string[] }[];
  todos: {
    priority: string;
    title: string;
    why: string;
    files?: string[];
  }[];
  tech_debt: { title: string; detail: string }[];
  risks: string[];
}

export interface AnalyzeOptions {
  path: string;
  model?: string;
  includeLlm?: boolean;
  signal?: AbortSignal;
  onEvent: (ev: AnalyzeProgressEvent) => void;
}

@Injectable({ providedIn: "root" })
export class ProjectAnalysisService {
  private http = inject(HttpClient);
  private settings = inject(SettingsService);

  private get base(): string {
    return this.settings.apiBaseUrl();
  }

  async analyze(opts: AnalyzeOptions): Promise<void> {
    const body = {
      path: opts.path,
      model: opts.model || undefined,
      include_llm: opts.includeLlm !== false,
    };
    let resp: Response;
    try {
      resp = await fetch(`${this.base}/analyze`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Accept: "text/event-stream",
        },
        body: JSON.stringify(body),
        signal: opts.signal,
      });
    } catch (e: unknown) {
      if ((e as Error).name === "AbortError") {
        opts.onEvent({ type: "cancelled" });
        return;
      }
      opts.onEvent({ type: "error", message: (e as Error).message });
      return;
    }

    if (!resp.ok || !resp.body) {
      const text = await resp.text().catch(() => "");
      opts.onEvent({
        type: "error",
        message: `HTTP ${resp.status} ${resp.statusText} ${text}`.trim(),
      });
      return;
    }

    const reader = resp.body.getReader();
    const decoder = new TextDecoder();
    let buf = "";
    try {
      while (true) {
        const { value, done } = await reader.read();
        if (done) break;
        buf += decoder.decode(value, { stream: true });
        let idx: number;
        while ((idx = buf.indexOf("\n\n")) !== -1) {
          const raw = buf.slice(0, idx).trim();
          buf = buf.slice(idx + 2);
          if (!raw.startsWith("data:")) continue;
          const json = raw.slice(5).trim();
          try {
            const ev = JSON.parse(json) as AnalyzeProgressEvent;
            opts.onEvent(ev);
          } catch {
            /* ignore parse error */
          }
        }
      }
    } catch (e: unknown) {
      if ((e as Error).name === "AbortError") {
        opts.onEvent({ type: "cancelled" });
        return;
      }
      opts.onEvent({ type: "error", message: (e as Error).message });
    }
  }

  getMemory(path: string): Promise<{
    ok: boolean;
    memory_dir: string;
    memory: ProjectMemory;
    markdown: Record<string, string>;
  }> {
    return firstValueFrom(
      this.http.get<{
        ok: boolean;
        memory_dir: string;
        memory: ProjectMemory;
        markdown: Record<string, string>;
      }>(`${this.base}/analyze/memory`, { params: { path } }),
    );
  }

  ask(
    path: string,
    question: string,
    model?: string,
  ): Promise<{ ok: boolean; answer: string }> {
    return firstValueFrom(
      this.http.post<{ ok: boolean; answer: string }>(
        `${this.base}/analyze/ask`,
        { path, question, model },
      ),
    );
  }
}

import {
  AfterViewChecked,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  OnInit,
  ViewChild,
  inject,
} from "@angular/core";
import { CommonModule } from "@angular/common";
import { ActivatedRoute } from "@angular/router";
import { ChatService } from "../../services/chat.service";
import { MessageComponent } from "../../components/message/message.component";
import {
  ChatInputComponent,
  SendPayload,
} from "../../components/chat-input/chat-input.component";

@Component({
  selector: "app-chat-page",
  standalone: true,
  imports: [CommonModule, MessageComponent, ChatInputComponent],
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <div class="flex h-full flex-col">
      <div #scroll class="flex-1 overflow-y-auto">
        <div class="mx-auto w-full max-w-3xl px-4">
          @if (!chat.active() || !chat.active()!.messages.length) {
            <div
              class="flex h-[60vh] flex-col items-center justify-center text-center text-slate-500"
            >
              <div
                class="mb-3 grid h-14 w-14 place-items-center rounded-2xl bg-brand-600 text-white text-2xl font-bold shadow-soft"
              >
                A
              </div>
              <h1
                class="text-2xl font-semibold text-slate-800 dark:text-slate-100"
              >
                How can I help you build today?
              </h1>
              <p class="mt-1 text-sm">
                Choose a model, describe what you need, and the agent will do
                the rest.
              </p>
              <div
                class="mt-6 grid w-full max-w-xl grid-cols-1 gap-2 sm:grid-cols-2"
              >
                @for (s of starters; track s) {
                  <button
                    class="card px-3 py-3 text-left text-sm hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
                    type="button"
                    (click)="sendText(s)"
                  >
                    {{ s }}
                  </button>
                }
              </div>
            </div>
          } @else {
            <div class="py-4">
              @for (m of chat.active()!.messages; track m.id) {
                <app-message [msg]="m" />
              }
              @if (showRegenerate()) {
                <div class="flex justify-center py-2">
                  <button
                    class="btn-ghost border border-slate-200 dark:border-slate-700"
                    type="button"
                    (click)="regenerate()"
                  >
                    ↻ Regenerate response
                  </button>
                </div>
              }
            </div>
          }
        </div>
      </div>

      <div
        class="border-t border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-950/70 backdrop-blur px-4 py-3"
      >
        <div class="mx-auto w-full max-w-3xl">
          <app-chat-input (sent)="send($event)" />
        </div>
      </div>
    </div>
  `,
})
export class ChatPageComponent implements OnInit, AfterViewChecked {
  @ViewChild("scroll") scroll!: ElementRef<HTMLDivElement>;
  protected chat = inject(ChatService);
  private route = inject(ActivatedRoute);

  protected starters = [
    "Build a FastAPI todo app with JWT auth and SQLite",
    "Explain async/await in Python with examples",
    "Write a TypeScript LRU cache with unit tests",
    "Refactor this code to use the strategy pattern",
  ];

  private lastLen = 0;

  ngOnInit(): void {
    this.route.paramMap.subscribe((p) => {
      const id = p.get("id");
      if (id) this.chat.select(id);
    });
  }

  ngAfterViewChecked(): void {
    const conv = this.chat.active();
    const len = conv?.messages.reduce((n, m) => n + m.content.length, 0) ?? 0;
    if (len !== this.lastLen) {
      this.lastLen = len;
      this.scrollToBottom();
    }
  }

  private scrollToBottom(): void {
    const el = this.scroll?.nativeElement;
    if (!el) return;
    queueMicrotask(() => {
      el.scrollTop = el.scrollHeight;
    });
  }

  protected showRegenerate(): boolean {
    if (this.chat.streaming()) return false;
    const conv = this.chat.active();
    if (!conv || !conv.messages.length) return false;
    return conv.messages[conv.messages.length - 1].role === "assistant";
  }

  protected send(payload: SendPayload): void {
    void this.chat.send(payload.text, payload.attachments);
  }

  protected sendText(text: string): void {
    void this.chat.send(text);
  }

  protected regenerate(): void {
    void this.chat.regenerate();
  }
}
